import { useMemo, useState } from 'react';
import { withTheme } from '@rjsf/core';
import type { ThemeProps } from '@rjsf/core';
import validator from '@rjsf/validator-ajv8';
import type { IChangeEvent } from '@rjsf/core';
import type { FormSchema } from '@/lib/form-builder-types/types';
import { toJsonSchema, toUiSchema, evaluateCondition } from '@/lib/form-builder-types/schema-builder';
import { localizeString } from '@/lib/form-builder-types/i18n';
import { formBuilderTheme } from './theme';

export type FormRendererProps = {
  schema: FormSchema;
  locale: string;
  baseLocale?: string;
  formData?: Record<string, unknown>;
  onChange?: (data: Record<string, unknown>) => void;
  onSubmit?: (data: Record<string, unknown>) => void;
  onError?: (errors: unknown[]) => void;
  className?: string;
  disabled?: boolean;
  /** Override individual widgets, fields, or templates. Merged on top of the default shadcn theme. */
  theme?: Partial<ThemeProps>;
  /** Replace the submit button with a custom element */
  submitButton?: React.ReactNode;
};

export const FormRenderer: React.FC<FormRendererProps> = ({
  schema,
  locale,
  baseLocale,
  formData: externalFormData,
  onChange,
  onSubmit,
  onError,
  className,
  disabled,
  theme: themeOverride,
  submitButton,
}) => {
  // Track live form data so we can evaluate conditions and hide/show fields dynamically.
  const [liveData, setLiveData] = useState<Record<string, unknown>>(externalFormData ?? {});

  const visibleSchema = useMemo<FormSchema>(() => ({
    ...schema,
    fields: schema.fields.filter((f) => evaluateCondition(f.condition, liveData)),
  }), [schema, liveData]);

  const jsonSchema = useMemo(() => toJsonSchema(visibleSchema, locale, baseLocale), [visibleSchema, locale, baseLocale]);
  const uiSchema = useMemo(() => toUiSchema(visibleSchema, locale, baseLocale), [visibleSchema, locale, baseLocale]);
  const submitLabel = localizeString(schema.submitLabel, locale, baseLocale) || 'Submit';

  const mergedTheme = useMemo<ThemeProps>(() => {
    if (!themeOverride) return formBuilderTheme;
    return {
      widgets: { ...formBuilderTheme.widgets, ...themeOverride.widgets },
      fields: { ...formBuilderTheme.fields, ...themeOverride.fields },
      templates: { ...formBuilderTheme.templates, ...themeOverride.templates },
    };
  }, [themeOverride]);

  const ThemedForm = useMemo(() => withTheme(mergedTheme), [mergedTheme]);

  return (
    <div className={className} data-testid="form-renderer">
      <ThemedForm
        schema={jsonSchema}
        uiSchema={uiSchema}
        validator={validator}
        formData={externalFormData ?? liveData}
        disabled={disabled}
        onChange={(e: IChangeEvent) => {
          setLiveData(e.formData);
          onChange?.(e.formData);
        }}
        onSubmit={(e: IChangeEvent) => onSubmit?.(e.formData)}
        onError={(errors: unknown[]) => onError?.(errors)}
      >
        {submitButton ?? (
          <button
            type="submit"
            disabled={disabled}
            className="bg-primary text-primary-foreground hover:bg-primary/90 focus-visible:ring-ring mt-4 inline-flex h-9 items-center justify-center rounded-md px-4 py-2 text-sm font-medium shadow-sm transition-colors focus-visible:outline-none focus-visible:ring-1 disabled:pointer-events-none disabled:opacity-50"
          >
            {submitLabel}
          </button>
        )}
      </ThemedForm>
    </div>
  );
};

import type { ThemeProps } from '@rjsf/core';
import { TextWidget } from './widgets/text-widget';
import { TextareaWidget } from './widgets/textarea-widget';
import { SelectWidget } from './widgets/select-widget';
import { CheckboxWidget } from './widgets/checkbox-widget';
import { RadioWidget } from './widgets/radio-widget';
import { DateWidget } from './widgets/date-widget';
import { FileWidget } from './widgets/file-widget';
import { HeadingField } from './fields/heading-field';
import { ParagraphField } from './fields/paragraph-field';
import { SeparatorField } from './fields/separator-field';
import { FieldTemplate } from './templates/field-template';
import { ObjectFieldTemplate } from './templates/object-template';
import { ArrayFieldTemplate } from './templates/array-template';

export const formBuilderTheme: ThemeProps = {
  widgets: {
    TextWidget,
    TextareaWidget,
    SelectWidget,
    CheckboxWidget,
    RadioWidget,
    DateWidget,
    FileWidget,
    EmailWidget: TextWidget,
    URLWidget: TextWidget,
  },
  fields: {
    HeadingField,
    ParagraphField,
    SeparatorField,
  },
  templates: {
    FieldTemplate,
    ObjectFieldTemplate,
    ArrayFieldTemplate,
  },
};

export {
  TextWidget,
  TextareaWidget,
  SelectWidget,
  CheckboxWidget,
  RadioWidget,
  DateWidget,
  FileWidget,
  HeadingField,
  ParagraphField,
  SeparatorField,
  FieldTemplate,
  ObjectFieldTemplate,
  ArrayFieldTemplate,
};

import type { WidgetProps } from '@rjsf/utils';
import { Input } from '@/components/ui/input';

export const TextWidget = (props: WidgetProps) => {
  const { id, value, required, disabled, readonly, onChange, onBlur, onFocus, placeholder, autofocus, schema } =
    props;

  const type = schema.format === 'email' ? 'email' : schema.format === 'tel' ? 'tel' : 'text';

  return (
    <Input
      id={id}
      type={type}
      value={value ?? ''}
      required={required}
      disabled={disabled || readonly}
      placeholder={placeholder}
      autoFocus={autofocus}
      onChange={(e) => onChange(e.target.value)}
      onBlur={(e) => onBlur?.(id, e.target.value)}
      onFocus={(e) => onFocus?.(id, e.target.value)}
    />
  );
};

import type { WidgetProps } from '@rjsf/utils';
import { Textarea } from '@/components/ui/textarea';

export const TextareaWidget = (props: WidgetProps) => {
  const { id, value, required, disabled, readonly, onChange, onBlur, onFocus, placeholder, autofocus } = props;

  return (
    <Textarea
      id={id}
      value={value ?? ''}
      required={required}
      disabled={disabled || readonly}
      placeholder={placeholder}
      autoFocus={autofocus}
      rows={4}
      onChange={(e) => onChange(e.target.value)}
      onBlur={(e) => onBlur?.(id, e.target.value)}
      onFocus={(e) => onFocus?.(id, e.target.value)}
    />
  );
};

import type { WidgetProps } from '@rjsf/utils';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';

export const SelectWidget = (props: WidgetProps) => {
  const { id, value, required, disabled, readonly, onChange, options, placeholder } = props;
  const { enumOptions } = options;

  return (
    <Select value={value ?? ''} onValueChange={onChange} disabled={disabled || readonly} required={required}>
      <SelectTrigger id={id} className="w-full">
        <SelectValue placeholder={placeholder || 'Select...'} />
      </SelectTrigger>
      <SelectContent>
        {enumOptions?.map(({ value: optValue, label }) => (
          <SelectItem key={optValue} value={optValue}>
            {label}
          </SelectItem>
        ))}
      </SelectContent>
    </Select>
  );
};

import type { WidgetProps } from '@rjsf/utils';
import { Checkbox } from '@/components/ui/checkbox';

export const CheckboxWidget = (props: WidgetProps) => {
  const { id, value, disabled, readonly, onChange, label } = props;

  return (
    <div className="flex items-center gap-2">
      <Checkbox
        id={id}
        checked={value ?? false}
        disabled={disabled || readonly}
        onCheckedChange={(checked) => onChange(checked === true)}
      />
      {label && (
        <label
          htmlFor={id}
          className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70"
        >
          {label}
        </label>
      )}
    </div>
  );
};

import type { WidgetProps } from '@rjsf/utils';
import { RadioGroup, RadioGroupItem } from '@/components/ui/radio-group';

export const RadioWidget = (props: WidgetProps) => {
  const { id, value, required, disabled, readonly, onChange, options } = props;
  const { enumOptions } = options;

  return (
    <RadioGroup
      id={id}
      value={value ?? ''}
      onValueChange={onChange}
      disabled={disabled || readonly}
      required={required}
      className="flex flex-col gap-2"
    >
      {enumOptions?.map(({ value: optValue, label }) => (
        <div key={optValue} className="flex items-center gap-2">
          <RadioGroupItem id={`${id}-${optValue}`} value={optValue} />
          <label htmlFor={`${id}-${optValue}`} className="text-sm font-medium leading-none">
            {label}
          </label>
        </div>
      ))}
    </RadioGroup>
  );
};

import type { WidgetProps } from '@rjsf/utils';
import { Input } from '@/components/ui/input';

export const DateWidget = (props: WidgetProps) => {
  const { id, value, required, disabled, readonly, onChange, onBlur, onFocus, autofocus } = props;

  return (
    <Input
      id={id}
      type="date"
      value={value ?? ''}
      required={required}
      disabled={disabled || readonly}
      autoFocus={autofocus}
      onChange={(e) => onChange(e.target.value)}
      onBlur={(e) => onBlur?.(id, e.target.value)}
      onFocus={(e) => onFocus?.(id, e.target.value)}
    />
  );
};

import type { WidgetProps } from '@rjsf/utils';
import { Input } from '@/components/ui/input';

export const FileWidget = (props: WidgetProps) => {
  const { id, required, disabled, readonly, onChange, autofocus } = props;

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) {
      onChange(undefined);
      return;
    }
    const reader = new FileReader();
    reader.onload = () => onChange(reader.result);
    reader.readAsDataURL(file);
  };

  return (
    <Input
      id={id}
      type="file"
      required={required}
      disabled={disabled || readonly}
      autoFocus={autofocus}
      onChange={handleChange}
    />
  );
};

import type { FieldProps } from '@rjsf/utils';

export const HeadingField = (props: FieldProps) => {
  const { schema } = props;

  return (
    <div className="mb-4">
      <h2 className="text-foreground text-xl font-semibold tracking-tight">{schema.title}</h2>
      {schema.description && <p className="text-muted-foreground mt-1 text-sm">{schema.description}</p>}
    </div>
  );
};

import type { FieldProps } from '@rjsf/utils';

export const ParagraphField = (props: FieldProps) => {
  const { schema } = props;

  return (
    <div className="mb-4">
      <p className="text-muted-foreground text-sm leading-relaxed">{schema.title}</p>
    </div>
  );
};

import type { FieldProps } from '@rjsf/utils';

export const SeparatorField = (_props: FieldProps) => {
  return (
    <div className="my-4" role="separator">
      <hr className="border-border" />
    </div>
  );
};

import type { FieldTemplateProps } from '@rjsf/utils';

export const FieldTemplate = (props: FieldTemplateProps) => {
  const { id, label, required, description, errors, children, schema, displayLabel } = props;

  if (schema.type === 'boolean') {
    return (
      <div className="mb-4">
        {children}
        {description && <div className="text-muted-foreground mt-1 text-xs">{description}</div>}
        {errors && <div className="text-destructive mt-1 text-xs">{errors}</div>}
      </div>
    );
  }

  return (
    <div className="mb-4">
      {displayLabel && label && (
        <label htmlFor={id} className="mb-1.5 block text-sm font-medium leading-none">
          {label}
          {required && <span className="text-destructive ml-0.5">*</span>}
        </label>
      )}
      {children}
      {description && <div className="text-muted-foreground mt-1 text-xs">{description}</div>}
      {errors && <div className="text-destructive mt-1 text-xs">{errors}</div>}
    </div>
  );
};

import type { ObjectFieldTemplateProps } from '@rjsf/utils';

export const ObjectFieldTemplate = (props: ObjectFieldTemplateProps) => {
  const { title, description, properties } = props;

  return (
    <fieldset className="space-y-0">
      {title && <legend className="mb-4 text-lg font-semibold">{title}</legend>}
      {description && <div className="text-muted-foreground mb-4 text-sm">{description}</div>}
      {properties.map((prop) => (
        <div key={prop.name}>{prop.content}</div>
      ))}
    </fieldset>
  );
};

import type { ArrayFieldTemplateProps } from '@rjsf/utils';

export const ArrayFieldTemplate = (props: ArrayFieldTemplateProps) => {
  const { title, items, canAdd, onAddClick } = props;

  return (
    <div className="mb-4">
      {title && <h3 className="mb-2 text-sm font-medium">{title}</h3>}
      <div className="space-y-2">{items}</div>
      {canAdd && (
        <button
          type="button"
          className="border-border hover:bg-accent mt-2 rounded-md border px-3 py-1.5 text-sm"
          onClick={onAddClick}
        >
          Add Item
        </button>
      )}
    </div>
  );
};
